// Created: 2026-05-12

/**
 * Telemetry HTTP sink — dual-write to yonatan-hq platform.
 *
 * Cross-Project Analytics today writes JSONL to ~/.claude/analytics/ via
 * appendAnalytics(). That gives a great per-machine view but no fleet-wide
 * aggregation. This sink mirrors each entry to platform's /api/hooks/cc-event
 * endpoint so the Intelligence Tab can deep-dive across all hosts.
 *
 * Design tenets (all enforced below):
 *
 *  1. Fire-and-forget. Never throws, never blocks the JSONL write. The local
 *     buffer remains the source of truth — the HTTP POST is best-effort.
 *  2. Off by default. Until ORK_HQ_TELEMETRY_URL is set (or HQ_API_URL when
 *     `ORK_HQ_TELEMETRY_USE_HQ_API=1`) AND a token resolves, this is a no-op.
 *  3. Privacy-preserving. The JSONL writer already SHA256-hashes project
 *     paths (`hashProject` in analytics.ts). We forward the entry as-is —
 *     no extra fields, no path reintroduction.
 *  4. Self-protecting. A circuit breaker (3 consecutive failures → 5 min
 *     cooldown) prevents endpoint downtime from amplifying into 194 hooks
 *     × dozens of events/min of failed connect storms.
 *
 * Mirrors the hq-ext-plugin postToIntelligenceTab pattern
 * (hooks/src/hook-utils.ts:195) verbatim where it makes sense — same wire
 * format, same auth, same circuit semantics.
 */

import { mkdirSync, readFileSync, writeFileSync, existsSync } from 'node:fs';
import { getHomeDir, joinPath } from './paths.js';

// ─── Configuration resolution ──────────────────────────────────────────────

/**
 * Resolve the dual-write endpoint URL.
 *
 * Order: `ORK_HQ_TELEMETRY_URL` (explicit opt-in) → `HQ_API_URL` (only when
 * `ORK_HQ_TELEMETRY_USE_HQ_API=1` so co-deployed hq-ext sessions can share a
 * single base URL) → null (disabled).
 */
export function resolveSinkUrl(): string | null {
  const explicit = process.env.ORK_HQ_TELEMETRY_URL;
  if (explicit) return explicit.replace(/\/$/, '');
  if (process.env.ORK_HQ_TELEMETRY_USE_HQ_API === '1' && process.env.HQ_API_URL) {
    return process.env.HQ_API_URL.replace(/\/$/, '');
  }
  return null;
}

/**
 * Resolve the shared bearer token. Mirrors hq-ext's resolveHooksToken so a
 * single secret rotation covers both pipelines. Returns null when no source
 * has a value — caller no-ops cleanly.
 */
export function resolveSinkToken(): string | null {
  if (process.env.CC_HOOKS_SECRET_TOKEN) return process.env.CC_HOOKS_SECRET_TOKEN;
  const pluginConfig = process.env.CLAUDE_PLUGIN_CONFIG;
  if (pluginConfig) {
    try {
      const cfg = JSON.parse(pluginConfig) as Record<string, unknown>;
      const tok = cfg.CC_HOOKS_SECRET_TOKEN;
      if (typeof tok === 'string' && tok) return tok;
    } catch {
      // fall through
    }
  }
  const cachePath = joinPath(getHomeDir(), '.claude', 'hooks', '.cc-hooks-token');
  if (existsSync(cachePath)) {
    const cached = readFileSync(cachePath, 'utf-8').trim();
    if (cached) return cached;
  }
  return null;
}

// ─── Filename → CCHookEvent mapping ────────────────────────────────────────

/**
 * Convert an analytics JSONL filename into the platform's CCHookEvent
 * wire value. `skill-usage.jsonl` → `OrkSkillUsage`.
 *
 * Mirrors the names registered in
 * yonatan-hq/platform: apps/api/app/schemas/cc_hooks/_enums.py.
 * Any filename that doesn't resolve to a known event returns null so the
 * sink no-ops rather than emitting a `Generic` row.
 */
const KNOWN_EVENT_FILES = new Set([
  'skill-usage.jsonl',
  'agent-usage.jsonl',
  'hook-timing.jsonl',
  'cache-breaks.jsonl',
  'secret-audit.jsonl',
  'dx-signals.jsonl',
  'session-summary.jsonl',
  'session-start-perf.jsonl',
  'team-activity.jsonl',
  'subagent-quality.jsonl',
  'task-usage.jsonl',
]);

export function fileToEventName(file: string): string | null {
  if (!KNOWN_EVENT_FILES.has(file)) return null;
  const base = file.replace(/\.jsonl$/, '');
  const pascal = base
    .split('-')
    .map((p) => p.charAt(0).toUpperCase() + p.slice(1))
    .join('');
  return `Ork${pascal}`;
}

// ─── Circuit breaker (3 failures → 5 min cooldown) ─────────────────────────

const FAILURE_THRESHOLD = 3;
const COOLDOWN_MS = 5 * 60 * 1000;

interface CircuitState {
  consecutiveFailures: number;
  openedAt: number | null;
}

function circuitStatePath(): string {
  return joinPath(getHomeDir(), '.claude', 'ork-telemetry', 'circuit.json');
}

function loadCircuitState(): CircuitState {
  try {
    const raw = readFileSync(circuitStatePath(), 'utf-8');
    const parsed = JSON.parse(raw) as Partial<CircuitState>;
    return {
      consecutiveFailures: typeof parsed.consecutiveFailures === 'number' ? parsed.consecutiveFailures : 0,
      openedAt: typeof parsed.openedAt === 'number' ? parsed.openedAt : null,
    };
  } catch {
    return { consecutiveFailures: 0, openedAt: null };
  }
}

function saveCircuitState(state: CircuitState): void {
  try {
    const p = circuitStatePath();
    mkdirSync(joinPath(getHomeDir(), '.claude', 'ork-telemetry'), { recursive: true });
    writeFileSync(p, JSON.stringify(state));
  } catch {
    // breaker is best-effort; failing to persist is acceptable
  }
}

export function isCircuitOpen(now = Date.now()): boolean {
  const state = loadCircuitState();
  if (state.openedAt === null) return false;
  if (now - state.openedAt > COOLDOWN_MS) return false; // half-open: allow probe
  return true;
}

export function recordSuccess(): void {
  saveCircuitState({ consecutiveFailures: 0, openedAt: null });
}

export function recordFailure(): void {
  const state = loadCircuitState();
  state.consecutiveFailures += 1;
  // Re-arm the cooldown on EVERY failure at/above the threshold — including a
  // failed half-open probe. The previous `&& openedAt === null` guard set
  // openedAt only once, so after the first cooldown elapsed the breaker stayed
  // permanently half-open: it probed (and failed) on every subsequent event,
  // letting consecutiveFailures climb unbounded (observed: 1786 since May 28)
  // instead of backing off for COOLDOWN_MS between probes.
  if (state.consecutiveFailures >= FAILURE_THRESHOLD) {
    state.openedAt = Date.now();
  }
  saveCircuitState(state);
}

// ─── The actual POST ───────────────────────────────────────────────────────

/**
 * Post one analytics entry to platform. Fire-and-forget. Returns immediately
 * with no Promise the caller has to await — the network call lives on the
 * event loop and dies silently if it fails.
 *
 * @param file   The JSONL filename (e.g. "skill-usage.jsonl") that originated
 *               this entry. Used to derive the platform event name.
 * @param entry  The same entry passed to appendAnalytics(). Forwarded
 *               verbatim as the payload's `data` field.
 */
export function postAnalyticsToSink(file: string, entry: Record<string, unknown>): void {
  const url = resolveSinkUrl();
  if (!url) return;

  const event = fileToEventName(file);
  if (!event) return;

  const token = resolveSinkToken();
  if (!token) return;

  if (isCircuitOpen()) return;

  const payload = {
    hook_event_name: event,
    session_id: process.env.CLAUDE_SESSION_ID || 'unknown',
    project: typeof entry.pid === 'string' ? entry.pid : 'unknown',
    timestamp: new Date().toISOString(),
    data: entry,
  };

  // Detach from any awaiting caller — pure side effect.
  void (async () => {
    try {
      const resp = await fetch(`${url}/api/hooks/cc-event/`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify(payload),
        signal: AbortSignal.timeout(3000),
      });
      if (resp.ok) recordSuccess();
      else recordFailure();
    } catch {
      recordFailure();
    }
  })();
}
